mapper.select:
select d.*
from io_order_detail d
         inner join io_order o on o.id = d.order_id
where d.delete_flag = 0
  and o.delete_flag = 0

    and d.product_id = #{query.productId}


    and o.biz_date  >=  #{query.bizDateStart}


    and o.biz_date  <=  #{query.bizDateEnd}


    and o.order_type = #{query.orderType}

order by d.id desc

select coalesce(sum(case
                        when d.order_type = 1 then d.qty
                        else -d.qty
    end), 0)
from io_order_detail d
where d.product_id = #{productId}
  and d.id < #{detailId}
  and delete_flag = 0

select t.id as detailId, coalesce(p.initial_stock, 0) + coalesce(sum(case when d.order_type = 1 then d.qty else -d.qty end), 0) as currentStockQty from io_order_detail t left join product p on p.id = t.product_id and p.delete_flag = 0 left join io_order_detail d on d.product_id = t.product_id and d.delete_flag = 0 and d.id <= t.id where t.delete_flag = 0 and t.id in
#{detailId}
group by t.id, p.initial_stock
